    controlFlowEdge(control, a1) and
    controlFlowEdge(control, a2) and
    a1 != a2 and
    isReachable(a1, dependent) and
    isReachable(a2, dependent) and
    not dominates(a1, dependent) and
    not dominates(a2, dependent))
}
